const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
if (!body.complaint_text) return { json: { _empty: true, status: 400, error: 'complaint_text required' } };
return { json: { token: token, policy_application_id: body.policy_application_id || null, client_id: body.client_id || null, advisor_id_subject: body.advisor_id_subject || null, complaint_text: String(body.complaint_text).slice(0, 4000), material: !!body.material, complaint_source: body.complaint_source || 'client_request' } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
const i = $('Extract Inputs').item.json;
return { json: { _ok: true, reporter_user_id: row.id || row.user_id, reporter_role: row.user_role, policy_application_id: i.policy_application_id, client_id: i.client_id || row.client_id, advisor_id_subject: i.advisor_id_subject, complaint_text: i.complaint_text, material: i.material, complaint_source: i.complaint_source } };
